import * as t from "io-ts";
import { BaseIntent } from "./baseIntent";
import { intentTypes } from "./intentType";
import { optionalString } from "../../../utils";

export const SignMessageIntent = t.intersection([
  BaseIntent,
  t.type({
    intentType: intentTypes.signMessage,
    /**
     * A plain text message
     * @example for EVM: test message
     */
    messageRaw: t.string,
    /**
     * An encoded string
     * @example for EVM: \x19Ethereum Signed Message:\n12test message
     */
    messageEncoded: optionalString,
    /**
     * The type of message standard, e.g. 'EIP191', 'EIP712', 'CIP8' etc.
     * @example for EVM: EIP191
     */
    messageStandardType: optionalString,
    /**
     * The address of the signer, could be the root address or a receive address of the wallet
     */
    signerAddress: optionalString,
  }),
]);

export type SignMessageIntent = t.TypeOf<typeof SignMessageIntent>;
